# AbletonOSC bridge (requires the AbletonOSC Remote Script installed in Live)
# Defaults (verify against the AbletonOSC README for your version):
#   TD -> Ableton  : UDP port 11000  (AbletonOSC listen port)
#   Ableton -> TD  : UDP port 11001  (AbletonOSC reply port)
#
# Wire an OSC Out DAT (par.address = Live's IP, par.port = 11000) and an
# OSC In DAT (par.port = 11001) to the helper below.

class AbletonOSCBridge:
    def __init__(self, oscOutDat, oscInDat=None):
        self.osc_out = oscOutDat
        self.osc_in = oscInDat
        self.tempo = 120.0
        self.playing = False

    # --- Control Live from TD ---
    # oscoutDAT.sendOSC(address, *values): values are unpacked positional args.
    def play(self):
        self.osc_out.sendOSC('/live/song/start_playing')

    def stop(self):
        self.osc_out.sendOSC('/live/song/stop_playing')

    def set_tempo(self, bpm):
        self.osc_out.sendOSC('/live/song/set/tempo', float(bpm))

    def fire_clip(self, track, clip):
        # AbletonOSC fires a clip slot via /live/clip_slot/fire track_index clip_index
        self.osc_out.sendOSC('/live/clip_slot/fire', int(track), int(clip))

    def stop_all_clips(self, track):
        self.osc_out.sendOSC('/live/track/stop_all_clips', int(track))

    def set_track_volume(self, track, volume):
        """volume: 0.0..1.0"""
        self.osc_out.sendOSC('/live/track/set/volume', int(track), float(volume))

    def set_device_param(self, track, device, param, value):
        """Set a device parameter value."""
        self.osc_out.sendOSC('/live/device/set/parameter/value',
                             int(track), int(device), int(param), float(value))

    # --- Query Live (responses come back on the OSC In DAT) ---
    def request_tempo(self):
        self.osc_out.sendOSC('/live/song/get/tempo')

# Handle replies in the OSC In DAT's Callbacks DAT.
# Verified signature (docs.derivative.ca/OscinDAT_Class):
def onReceiveOSC(dat, rowIndex, message, bytes, timeStamp, address, args, peer):
    if address == '/live/song/get/tempo' and args:
        op('bpm_display').par.value0 = float(args[0])
    elif address == '/live/song/get/is_playing' and args:
        pass  # bool(args[0])
